import{_ as e,o as t,c as n,S as i}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"Multi-Agent 系统","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_29-multi_agent.md","filePath":"直击概念/17ai/s_ai_29-multi_agent.md","lastUpdated":1778207238000}'),s={name:"直击概念/17ai/s_ai_29-multi_agent.md"};function r(l,a,o,h,g,d){return t(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="multi-agent-系统" tabindex="-1">Multi-Agent 系统 <a class="header-anchor" href="#multi-agent-系统" aria-label="Permalink to &quot;Multi-Agent 系统&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>Multi-Agent 系统是将多个 AI Agent 组织起来<strong>分工协作</strong>完成复杂任务的架构模式。每个 Agent 有自己的角色、职责和工具集，通过通信和协调共同解决问题。</p><p>类比：一个软件团队有产品经理、前端、后端、QA——各司其职，通过沟通完成任务。Multi-Agent 同理。</p><h2 id="为什么需要-multi-agent" tabindex="-1">为什么需要 Multi-Agent <a class="header-anchor" href="#为什么需要-multi-agent" aria-label="Permalink to &quot;为什么需要 Multi-Agent&quot;">​</a></h2><p>单 Agent 的局限性：</p><ul><li><strong>上下文溢出</strong>：单次对话无法装下复杂任务的所有信息</li><li><strong>角色冲突</strong>：一个模型很难同时扮演产品、开发、测试</li><li><strong>能力边界</strong>：不同 Agent 可使用不同的模型（便宜模型做简单任务，强模型做推理）</li><li><strong>可靠性</strong>：Agent 间互相检查，减少错误</li></ul><h2 id="核心架构模式" tabindex="-1">核心架构模式 <a class="header-anchor" href="#核心架构模式" aria-label="Permalink to &quot;核心架构模式&quot;">​</a></h2><h3 id="顺序编排-sequential" tabindex="-1">顺序编排（Sequential） <a class="header-anchor" href="#顺序编排-sequential" aria-label="Permalink to &quot;顺序编排（Sequential）&quot;">​</a></h3><p>Agent A → Agent B → Agent C → 结果</p><p>流水线模式，适合有明确阶段的流程：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>需求分析 Agent → 技术方案 Agent → 代码生成 Agent → 代码审查 Agent</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="路由-分发-router" tabindex="-1">路由/分发（Router） <a class="header-anchor" href="#路由-分发-router" aria-label="Permalink to &quot;路由/分发（Router）&quot;">​</a></h3><p>根据任务类型分发给专门的 Agent：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>用户提问 → 路由器</span></span>
<span class="line"><span>    ├→ 前端 Agent（React 问题）</span></span>
<span class="line"><span>    ├→ 后端 Agent（API 问题）</span></span>
<span class="line"><span>    └→ DevOps Agent（部署问题）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="层级-管理-hierarchical" tabindex="-1">层级/管理（Hierarchical） <a class="header-anchor" href="#层级-管理-hierarchical" aria-label="Permalink to &quot;层级/管理（Hierarchical）&quot;">​</a></h3><p>一个管理者 Agent 调度多个子 Agent：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>            管理 Agent</span></span>
<span class="line"><span>          /    |     \\</span></span>
<span class="line"><span>    子Agent1  子Agent2  子Agent3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>管理 Agent 负责任务分解、分配、结果整合。</p><h3 id="协作-辩论-collaborative" tabindex="-1">协作/辩论（Collaborative） <a class="header-anchor" href="#协作-辩论-collaborative" aria-label="Permalink to &quot;协作/辩论（Collaborative）&quot;">​</a></h3><p>多个 Agent 自由对话，形成共识：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>Agent A 提出方案 → Agent B 质疑 → Agent C 补充 → Agent A 修正 → 共识</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="群集-蜂群-swarm" tabindex="-1">群集/蜂群（Swarm） <a class="header-anchor" href="#群集-蜂群-swarm" aria-label="Permalink to &quot;群集/蜂群（Swarm）&quot;">​</a></h3><p>大量轻量 Agent 各自执行小任务，结果聚合。</p><h2 id="通信机制" tabindex="-1">通信机制 <a class="header-anchor" href="#通信机制" aria-label="Permalink to &quot;通信机制&quot;">​</a></h2><h3 id="共享上下文" tabindex="-1">共享上下文 <a class="header-anchor" href="#共享上下文" aria-label="Permalink to &quot;共享上下文&quot;">​</a></h3><p>所有 Agent 写入共享的消息池，彼此可见。</p><h3 id="消息传递" tabindex="-1">消息传递 <a class="header-anchor" href="#消息传递" aria-label="Permalink to &quot;消息传递&quot;">​</a></h3><p>Agent 间通过结构化消息（JSON）定向通信。</p><h3 id="协议标准" tabindex="-1">协议标准 <a class="header-anchor" href="#协议标准" aria-label="Permalink to &quot;协议标准&quot;">​</a></h3><ul><li><strong>A2A（Agent-to-Agent）</strong>：Google 提出的 Agent 间通信协议</li><li><strong>MCP</strong>：Agent 与外部工具的通信协议</li><li>两者互补：MCP 连接工具，A2A 连接 Agent</li></ul><h2 id="实现框架" tabindex="-1">实现框架 <a class="header-anchor" href="#实现框架" aria-label="Permalink to &quot;实现框架&quot;">​</a></h2><table><thead><tr><th>框架</th><th>特点</th></tr></thead><tbody><tr><td><strong>LangGraph</strong></td><td>Python/JS，状态图驱动</td></tr><tr><td><strong>CrewAI</strong></td><td>Python，角色驱动的简单抽象</td></tr><tr><td><strong>AutoGen</strong></td><td>微软，对话驱动</td></tr><tr><td><strong>MetaGPT</strong></td><td>模拟软件公司 SOP 流程</td></tr><tr><td><strong>OpenAI Swarm</strong></td><td>轻量实验性框架</td></tr><tr><td><strong>Vercel AI SDK</strong></td><td>前端友好，支持 Agent 模式</td></tr></tbody></table><h2 id="前端应用场景" tabindex="-1">前端应用场景 <a class="header-anchor" href="#前端应用场景" aria-label="Permalink to &quot;前端应用场景&quot;">​</a></h2><ul><li><strong>全栈开发 Agent 团队</strong>：需求→UI 设计→前端代码→后端 API→测试</li><li><strong>代码 Review Agent 系统</strong>：代码提交后多个审查 Agent 并行检查（性能、安全、可访问性等）</li><li><strong>客服升级系统</strong>：简单问题 → 基础 Agent，复杂问题 → 专家 Agent，敏感问题 → 人工</li></ul><h2 id="主要挑战" tabindex="-1">主要挑战 <a class="header-anchor" href="#主要挑战" aria-label="Permalink to &quot;主要挑战&quot;">​</a></h2><ul><li><strong>协调复杂度</strong>：Agent 数量增加，协调成本指数级上升</li><li><strong>成本控制</strong>：多 Agent 意味着多次 LLM 调用</li><li><strong>一致性</strong>：多个 Agent 对同一问题可能给出矛盾答案</li><li><strong>循环死锁</strong>：Agent 间可能陷入无效争论</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>什么时候应该用 Multi-Agent 而不是单 Agent？</li><li>Multi-Agent 的几种架构模式？各适合什么场景？</li><li>A2A 协议解决的是什么问题？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://www.anthropic.com/research/building-effective-agents" target="_blank" rel="noreferrer">Building effective agents - Anthropic</a></li><li><a href="https://langchain-ai.github.io/langgraph/tutorials/multi_agent/" target="_blank" rel="noreferrer">LangGraph Multi-Agent</a></li><li><a href="https://developers.googleblog.com/en/a2a-a-new-era-of-agent-interoperability/" target="_blank" rel="noreferrer">A2A Protocol</a></li></ul>`,41)])])}const c=e(s,[["render",r]]);export{u as __pageData,c as default};
